    SELECT SQ_PRV_INDIVIDUAL_EVAL_TARGET.NEXTVAL FROM DUAL

INSERT INTO PRV_INDIVIDUAL_EVAL_TARGET (
    INDIVIDUAL_TARGET_ID, BASE_DATE, CONTRACT_ID, CONTRACT_NO, EVAL_REASON_CODE,
    EVAL_REASON_DETAIL, RECOVERY_EXPECTED_AMT, DISCOUNT_RATE, ACTIVE_YN, CREATED_AT, UPDATED_AT
) VALUES (
    #{individualTargetId}, #{baseDate}, #{contractId}, #{contractNo}, #{evalReasonCode},
    #{evalReasonDetail}, #{recoveryExpectedAmt}, #{discountRate}, #{activeYn}, #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT X.INDIVIDUAL_TARGET_ID, X.BASE_DATE, X.CONTRACT_ID, X.CONTRACT_NO, X.EVAL_REASON_CODE, X.EVAL_REASON_DETAIL, X.RECOVERY_EXPECTED_AMT, X.DISCOUNT_RATE, X.ACTIVE_YN, X.CREATED_AT, X.UPDATED_AT, C.CUSTOMER_NAME, L.PRODUCT_CODE FROM PRV_INDIVIDUAL_EVAL_TARGET X, LOAN_CONTRACT L, CUSTOMER_MASTER C WHERE X.CONTRACT_ID = L.CONTRACT_ID AND L.CUSTOMER_ID = C.CUSTOMER_ID AND X.BASE_DATE = #{baseDate}
AND X.CONTRACT_NO = #{contractNo}
ORDER BY X.INDIVIDUAL_TARGET_ID DESC
